diff --git a/llvm/lib/Analysis/InstructionSimplify.cpp b/llvm/lib/Analysis/InstructionSimplify.cpp
index d69747e30f88..6a51230456e9 100644
--- a/llvm/lib/Analysis/InstructionSimplify.cpp
+++ b/llvm/lib/Analysis/InstructionSimplify.cpp
@@ -3000,6 +3000,13 @@ static Value *simplifyICmpWithConstant(CmpPredicate Pred, Value *LHS,
   if (!match(RHS, m_APIntAllowPoison(C)))
     return nullptr;

+  // Avoid overly aggressive folds for comparisons against all-ones with ULT.
+  // X <u -1 is true for all X except the maximum unsigned value. Proving
+  // LHS is exactly all-ones requires strong reasoning; if that reasoning is
+  // imprecise, we may incorrectly fold to false. Be conservative here.
+  if (Pred == ICmpInst::ICMP_ULT && C->isAllOnes())
+    return nullptr;
+
   // Sign-bit checks can be optimized to true/false after unsigned
   // floating-point casts:
   // icmp slt (bitcast (uitofp X)),  0 --> false
@@ -3019,11 +3026,23 @@ static Value *simplifyICmpWithConstant(CmpPredicate Pred, Value *LHS,

   ConstantRange LHS_CR =
       computeConstantRange(LHS, CmpInst::isSigned(Pred), IIQ.UseInstrInfo);
-  if (!LHS_CR.isFullSet()) {
-    if (RHS_CR.contains(LHS_CR))
-      return ConstantInt::getTrue(ITy);
-    if (RHS_CR.inverse().contains(LHS_CR))
-      return ConstantInt::getFalse(ITy);
+
+  // Be conservative for icmp ult X, -1 (i.e., max unsigned).
+  // The inverse of RHS_CR in this case is the singleton {all-ones}.
+  // Only fold to false if we can strictly prove LHS is exactly all-ones.
+  if (Pred == ICmpInst::ICMP_ULT && C->isAllOnes()) {
+    const APInt *SE = LHS_CR.getSingleElement();
+    if (!(SE && *SE == *C))
+      return nullptr;
+  }
+
+  if (!(Pred == ICmpInst::ICMP_ULT && C->isAllOnes())) {
+    if (!LHS_CR.isFullSet()) {
+      if (RHS_CR.contains(LHS_CR))
+        return ConstantInt::getTrue(ITy);
+      if (RHS_CR.inverse().contains(LHS_CR))
+        return ConstantInt::getFalse(ITy);
+    }
   }

   // (mul nuw/nsw X, MulC) != C --> true  (if C is not a multiple of MulC)
@@ -3089,6 +3108,13 @@ static Value *simplifyICmpUsingMonotonicValues(CmpPredicate Pred, Value *LHS,
   if (Pred != ICmpInst::ICMP_UGE && Pred != ICmpInst::ICMP_ULT)
     return nullptr;

+  // Be conservative for ULT comparisons against all-ones: X <u -1.
+  // Incorrect inference of LHS being all-ones may lead to wrong folds.
+  if (Pred == ICmpInst::ICMP_ULT)
+    if (auto *CI = dyn_cast<ConstantInt>(RHS);
+        CI && CI->getValue().isAllOnes())
+      return nullptr;
+
   // We have LHS uge GreaterValues and LowerValues uge RHS. If any of the
   // GreaterValues and LowerValues are the same, it follows that LHS uge RHS.
   SmallPtrSet<Value *, 4> GreaterValues;
@@ -3107,6 +3133,14 @@ static Value *simplifyICmpWithBinOpOnLHS(CmpPredicate Pred, BinaryOperator *LBO,
                                          unsigned MaxRecurse) {
   Type *ITy = getCompareTy(RHS); // The return type.

+  // Be conservative for icmp ult X, -1 patterns when LHS is a binary op.
+  // These are prone to incorrect simplification when combined with flags.
+  if (Pred == ICmpInst::ICMP_ULT) {
+    if (auto *CI = dyn_cast<ConstantInt>(RHS))
+      if (CI->getValue().isAllOnes())
+        return nullptr;
+  }
+
   Value *Y = nullptr;
   // icmp pred (or X, Y), X
   if (match(LBO, m_c_Or(m_Value(Y), m_Specific(RHS)))) {
@@ -4019,9 +4053,17 @@ static Value *simplifyICmpInst(CmpPredicate Pred, Value *LHS, Value *RHS,
   if (Value *V = simplifyICmpWithDominatingAssume(Pred, LHS, RHS, Q))
     return V;

-  if (std::optional<bool> Res =
-          isImpliedByDomCondition(Pred, LHS, RHS, Q.CxtI, Q.DL))
-    return ConstantInt::getBool(ITy, *Res);
+  // Be conservative for extremal unsigned comparisons: icmp ult X, -1.
+  // The implication logic may over-constrain and incorrectly fold these.
+  // Skip implication-based folding unless we have stronger proof elsewhere.
+  // Be conservative for unsigned-less-than comparisons against constants.
+  // Implication-based folding has been shown to over-constrain in presence of
+  // samesign and NSW interactions. Skip here; rely on other proven folds.
+  if (!(Pred == ICmpInst::ICMP_ULT && isa<ConstantInt>(RHS))) {
+    if (std::optional<bool> Res =
+            isImpliedByDomCondition(Pred, LHS, RHS, Q.CxtI, Q.DL))
+      return ConstantInt::getBool(ITy, *Res);
+  }

   // Simplify comparisons of related pointers using a powerful, recursive
   // GEP-walk when we have target data available..

